scwin.f_Retrieve = async function (e) {
  if (lc_qryConKnd.getValue() == "전표번호") {
    let ret = await $c.gus.cfValidate($p, [ibx_ed_slipNo]);
    if (!ret) {
      return;
    }
  } else if (lc_qryConKnd.getValue() == "공급일자") {
    if ($c.gus.cfIsNull($p, ed_spplyDtSt.getValue())) {
      await $c.win.alert($p, "공급일자는 필수 입니다.");
      ed_spplyDtSt.focus();
      return;
    }
    if ($c.gus.cfIsNull($p, ed_spplyDtEnd.getValue())) {
      await $c.win.alert($p, "공급일자는 필수 입니다.");
      ed_spplyDtEnd.focus();
      return;
    }
    /*
    let ret = $c.gus.cfValidateValue(ed_spplyDtSt.getValue().trim().replace(" ",""), "date=YYYYMMDD");
    if(!ret){
       await $c.win.alert("공급일자가 날자 형식에 맞지 않습니다.");
       ed_spplyDtSt.focus();
       return;
    }
    */

    var fromDt = ed_spplyDtSt.getValue();
    if (!$c.date.isDate($p, fromDt)) {
      await $c.win.alert($p, "공급일자가 날자 형식에 맞지 않습니다.");
      ed_spplyDtSt.focus();
      return;
    }

    /*
    ret = $c.gus.cfValidateValue(ed_spplyDtEnd.getValue().trim().replace(" ",""), "date=YYYYMMDD");
     if(!ret){
       await $c.win.alert("공급일자가 날자 형식에 맞지 않습니다.");
       ed_spplyDtEnd.focus();
       return;
    }
    */

    var endDt = ed_spplyDtEnd.getValue();
    if (!$c.date.isDate($p, endDt)) {
      await $c.win.alert($p, "공급일자가 날자 형식에 맞지 않습니다.");
      ed_spplyDtEnd.focus();
      return;
    }

    //조회시작일자가 더 클경우 체크
    if (!$c.gus.cfIsAfterDate($p, ed_spplyDtSt.getValue(), ed_spplyDtEnd.getValue())) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
      return;
    }
  }
  ds_accountDetail.removeAll();
  dma_accountDetail.set("documentidentifier", "");
  dma_accountDetail.set("slipNo", "");
  dma_accountDetail.set("documentfunccode", "");
  dma_accountDetail.set("demandercontact", "");
  dma_accountDetail.set("sellPshcCd", "");
  dma_accountDetail.set("acctDeptNm", "");
  dma_accountDetail.set("drawEmpNo", "");
  dma_accountDetail.set("drawEmpNm", "");
  dma_accountDetail.set("demanderidentifier", "");
  dma_accountDetail.set("supplyamount", "");
  dma_accountDetail.set("taxamount", "");
  dma_accountDetail.set("spplyDt", "");
  dma_accountDetail.set("modRsnCd", "");
  dma_accountDetail.set("clntNo", "");
  dma_accountDetail.set("clntNm", "");
  dma_accountDetail.set("orgVatNo", "");
  dma_accountDetail.set("amendmentstatuscode", "");
  dma_accountDetail.set("demanderperson", "");
  dma_accountDetail.set("demanderdepartment", "");
  dma_accountDetail.set("remark", "");
  dma_accountDetail.set("demandercorpregnum", "");
  dma_accountDetail.set("coCdTemp", "");
  dma_search.set("slipNo", ibx_ed_slipNo.getValue());
  scwin.isRetrieve = true;
  //submit 처리.
  let objSubmit = await $c.sbm.execute($p, sbm_search);
  if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
    await scwin.sbm_search_submitdone();
  }
};
