//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  if (ds_accountDetail.getRowCount() == 0) {
    await $c.win.alert($p, "조회된 내역이 없습니다.");
    return;
  }
  if ($c.gus.cfIsNull($p, dma_accountDetail.get("spplyDt"))) {
    await $c.win.alert($p, "공급일자는 필수 입니다.");
    ibx_supplyDt.focus();
    return;
  }
  var spplyDt = dma_accountDetail.get("spplyDt").trim().replace(" ", "");
  if (!$c.date.isDate($p, spplyDt) || spplyDt.length != 8) {
    await $c.win.alert($p, "공급일자가 날자 형식에 맞지 않습니다.");
    ibx_supplyDt.focus();
    return;
  }

  /*
  var orgSpplyDtMonth = scwin.ibx_supplyDt_oldVal.substring(4,6);
  var spplyDtMonth = dma_accountDetail.get("spplyDt").substring(4,6);
  
  if(orgSpplyDtMonth != spplyDtMonth){
      await $c.win.alert("공급일자는 같은 월만 변경 가능 합니다.\n\n다른 월로 변경할 시에는 재경에 문의 하시기 바랍니다.");
      return;
  }
  */

  // 공급하는자종사업장번호 체크
  var demandercorpregnum_NumChk = /^[0-9]{0,4}$/; // 종사업장번호 패턴
  var demandercorpregnum_Check = ibx_demandercorpregnum.getValue();
  if (!demandercorpregnum_NumChk.test(demandercorpregnum_Check)) {
    await $c.win.alert($p, "종사업장번호는 4자리 숫자로 입력해주십시오.");
    return;
  }
  dma_accountDetail.set("coCdTemp", ed_coCd.getValue());
  let rtn = await $c.win.confirm($p, "거래처 재발급을 하시겠습니까?");
  if (!rtn) {
    return;
  }

  //submit 처리.
  let objSubmit = await $c.sbm.execute($p, sbm_saveAccount);
  if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
    await scwin.sbm_saveAccount_submitdone();
  }
};
scwin.sbm_saveAccount_submitdone = async function (e) {
  await $c.gus.cfAlertMsg($p, MSG_CM_INF_001);
};

//-------------------------------------------------------------------------
// 팝업
