scwin.f_openPopUp = async function (callObj, flag, check) {
  switch (flag) {
    // 거래처사업자번호 팝업
    case "1":
      var param = "";
      callObj.setSelectId("retrieveCrnInfo");
      scwin.udc_objNm = "udc_crn";
      await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc, ed_crn.getValue().trim(), ed_crnNm.getValue(), check, null, null, null, null, param, null, null, null, null);
      break;

    // 작성자 팝업
    case "2":
      callObj.setSelectId("retrieveAcEmpInfo");
      scwin.udc_objNm = "udc_drawEmp";
      await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc, ed_drawEmpNo.getValue().trim(), ed_drawEmpNm.getValue(), check, null, null, null, null, param, null, null, null, null);
      break;

    // E-mail 팝업
    case "3":
      if (ds_accountDetail.getRowCount() == 0) {
        return;
      }
      // 거래처 email 조회
      var where = "";
      var code = ds_accountDetail.getCellData(0, "clntNo");
      var name = ds_accountDetail.getCellData(0, "clntNm");
      callObj.setSelectId("retrieveClntEmail");
      scwin.udc_objNm = "udc_email";
      await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc, code, "", "F", null, null, null, null, null, null, null, null, null);
      break;
  }
};
scwin.udc_AllInOne_callBackFunc = function (rtnList) {
  let codeObj;
  let nameObj;
  if (scwin.udc_objNm == "udc_crn") {
    codeObj = ed_crn;
    nameObj = ed_crnNm;
    scwin.f_resultPopEd(codeObj, nameObj, ed_crn_H, rtnList);
  } else if (scwin.udc_objNm == "udc_drawEmp") {
    codeObj = ed_drawEmpNo;
    nameObj = ed_drawEmpNm;
    scwin.f_resultPopEd(codeObj, nameObj, ed_drawEmpNo_H, rtnList);
  } else if (scwin.udc_objNm == "udc_email") {
    if (typeof rtnList != "undefined") {
      if (rtnList != null) {
        if (rtnList[0] == "N/A") {
          return;
        }
        ibx_email.setValue(rtnList[0]);
        ibx_hid_demanderperson.setValue(rtnList[3]);
        ibx_hid_demanderdepartment.setValue(rtnList[4]);
      } else {}
    }
  }
};

//-------------------------------------------------------------------------
// 팝업체크
//-------------------------------------------------------------------------
scwin.f_checkPopEd = async function (callObj, strCd, strNm, hiddenCd, flag) {
  if (strCd.getValue().trim() == hiddenCd.getValue()) {
    return;
  }
  strNm.setValue("");
  hiddenCd.setValue("");
  if (strCd.getValue().trim() != "") {
    await scwin.f_openPopUp(callObj, flag, 'T');
  }
};

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function (strCd, strNm, hiddenCd, rtnList) {
  if (rtnList != null) {
    if (rtnList[0] == "N/A") {
      return;
    }
    strCd.setValue(rtnList[0]); // 코드
    strNm.setValue(rtnList[1]); // 명
    hiddenCd.setValue(rtnList[0]); // 히든값
  } else {
    strCd.setValue("");
    strNm.setValue("");
    hiddenCd.setValue("");
  }
};

